interface Component { render(): string }

class SimpleWindow implements Component {
  render() { return 'window' }
}

class Border implements Component {
  constructor(private inner: Component) {}
  render() { return this.inner.render() + ' + border' }
}

const w = new Border(new SimpleWindow())
console.log(w.render())

class Notifier { send(msg: string) { /* send base */ } }

// We want optional behaviors: encryption, logging, and rate-limiting
// that can be combined in different combinations at runtime.

// Version A: subclass-per-combination
class Notifier { send(msg: string) { /* send */ } }
class LoggedNotifier extends Notifier { send(m: string) { /* log */ super.send(m) } }
class EncryptedLoggedNotifier extends LoggedNotifier { send(m: string) { /* encrypt */ super.send(m) } }

// Version B: small wrappers that implement the same interface
interface INotifier { send(msg: string): void }
class BaseNotifier implements INotifier { send(m: string) { /* send */ } }
class LoggingWrapper implements INotifier {
  constructor(private inner: INotifier) {}
  send(m: string) { /* log */ this.inner.send(m) }
}
class EncryptionWrapper implements INotifier {
  constructor(private inner: INotifier) {}
  send(m: string) { /* encrypt */ this.inner.send(m) }
}
